import ast
from typing import Dict, List

class CyclomaticComplexityVisitor(ast.NodeVisitor):
    """AST visitor to calculate cyclomatic complexity."""

    def __init__(self):
        self.complexities: Dict[str, int] = {}
        self.current_function = None

    def visit_FunctionDef(self, node: ast.FunctionDef):
        """Visit function definition and calculate complexity."""
        old_function = self.current_function
        self.current_function = node.name

        # Base complexity is 1
        complexity = 1

        # Count decision points
        complexity += self._count_decision_points(node)

        self.complexities[node.name] = complexity

        # Continue visiting child nodes
        self.generic_visit(node)
        self.current_function = old_function

    def visit_AsyncFunctionDef(self, node: ast.AsyncFunctionDef):
        """Handle async function definitions."""
        self.visit_FunctionDef(node)

    def _count_decision_points(self, node: ast.AST) -> int:
        """Recursively count decision points in AST."""
        count = 0

        for child in ast.walk(node):
            # Decision-making nodes
            if isinstance(child, (ast.If, ast.While, ast.For, ast.ExceptHandler)):
                count += 1
            elif isinstance(child, ast.BoolOp):
                # and/or operations add complexity
                count += len(child.values) - 1
            elif isinstance(child, (ast.Assert, ast.With)):
                count += 1

        return count

def calculate_cyclomatic_complexity(source_code: str) -> Dict[str, int]:
    """Calculate cyclomatic complexity for all functions in source code."""
    tree = ast.parse(source_code)
    visitor = CyclomaticComplexityVisitor()
    visitor.visit(tree)
    return visitor.complexities

