if __name__ == "__main__":
    complexities = calculate_cyclomatic_complexity(sample_code)

    print("=== Cyclomatic Complexity ===")
    for func, complexity in complexities.items():
        risk = "Low"
        if complexity > 10:
            risk = "High"
        elif complexity > 5:
            risk = "Moderate"
        print(f"{func}: {complexity} (Risk: {risk})")

    print("\n=== Complexity Guidelines ===")
    print("1-10: Low risk (simple, well-structured)")
    print("11-20: Moderate risk (moderate complexity)")
    print("21+: High risk (difficult to test/maintain)")

import ast
import math
from typing import Dict

class MaintainabilityIndexCalculator:
    """Calculate Maintainability Index for Python source code."""

    def __init__(self, source_code: str):
        self.source_code = source_code
        self.tree = ast.parse(source_code)
        self.total_lines = len(source_code.splitlines())

    def calculate_halstead_volume(self) -> float:
        """Calculate Halstead Volume (V) based on operators and operands."""
        operators = set()
        operands = set()

        for node in ast.walk(self.tree):
            # Count operators
            if isinstance(node, (ast.BinOp, ast.UnaryOp, ast.BoolOp, ast.Compare)):
                operators.add(type(node).__name__)
            if isinstance(node, (ast.If, ast.While, ast.For, ast.With)):
                operators.add(type(node).__name__)

            # Count operands (variables, constants)
            if isinstance(node, ast.Name):
                operands.add(node.id)
            elif isinstance(node, ast.Constant):
                operands.add(str(node.value))

        n1 = len(operators)  # unique operators
        n2 = len(operands)  # unique operands
        N1 = sum(1 for _ in ast.walk(self.tree) if isinstance(_, (ast.BinOp, ast.UnaryOp, 
                         ast.BoolOp, ast.Compare, ast.If, ast.While, ast.For, ast.With)))
        N2 = sum(1 for _ in ast.walk(self.tree) if isinstance(_, (ast.Name, ast.Constant)))

        if n1 == 0 or n2 == 0:
            return 0

        volume = (N1 + N2) * math.log2(n1 + n2) if (n1 + n2) > 0 else 0
        return volume

    def calculate_cyclomatic_complexity(self) -> int:
        """Calculate Cyclomatic Complexity (CC)."""
        complexity = 1  # Base complexity

        for node in ast.walk(self.tree):
            if isinstance(node, (ast.If, ast.While, ast.For, ast.ExceptHandler)):
                complexity += 1
            elif isinstance(node, ast.BoolOp):
                complexity += len(node.values) - 1

        return complexity

    def calculate_maintainability_index(self) -> Dict:
        """Calculate the Maintainability Index (MI).

        MI Formula (Microsoft version):
        MI = 171 - 5.2 * ln(V) - 0.23 * CC - 16.2 * ln(LOC)

        Where:
        - V = Halstead Volume
        - CC = Cyclomatic Complexity
        - LOC = Lines of Code

        Adjusted for 0-100 scale with factor 100/171
        """
        volume = self.calculate_halstead_volume()
        cc = self.calculate_cyclomatic_complexity()
        loc = self.total_lines

        if loc <= 0 or volume <= 0:
            mi = 100.0  # Empty file is maximally maintainable
        else:
            # Calculate MI (original formula)
            mi = (171 
                  - 5.2 * math.log(volume) 
                  - 0.23 * cc 
                  - 16.2 * math.log(loc)) * (100 / 171)

        # Clamp to 0-100 range
        mi = max(0, min(100, mi))

        return {
            'maintainability_index': round(mi, 2),
            'halstead_volume': round(volume, 2),
            'cyclomatic_complexity': cc,
            'lines_of_code': loc,
            'rating': self._get_rating(mi)
        }

    def _get_rating(self, mi: float) -> str:
        """Get maintainability rating based on MI score."""
        if mi >= 85:
            return "Excellent"
        elif mi >= 65:
            return "Good"
        elif mi >= 45:
            return "Moderate"
        elif mi >= 25:
            return "Poor"
        else:
            return "Very Poor"

