    calc = MaintainabilityIndexCalculator(sample_code)
    metrics = calc.calculate_maintainability_index()

    print("=== Maintainability Index Analysis ===")
    print(f"Lines of Code: {metrics['lines_of_code']}")
    print(f"Cyclomatic Complexity: {metrics['cyclomatic_complexity']}")
    print(f"Halstead Volume: {metrics['halstead_volume']}")
    print(f"\n>>> MAINTAINABILITY INDEX: {metrics['maintainability_index']}")
    print(f">>> RATING: {metrics['rating']}")

    print("\n=== Rating Scale ===")
    print("85-100: Excellent (highly maintainable)")
    print("65-84: Good (maintainable with minor issues)")
    print("45-64: Moderate (maintainability concerns)")
    print("25-44: Poor (difficult to maintain)")
    print("0-24: Very Poor (require immediate refactoring)")
